struct APIConfig {
    var baseURL: URL
    var apiKey: String
    var pinnedSPKIHashesBase64: Set<String>
    var requestTimeout: TimeInterval = 20
}

final class PinnedSessionDelegate: NSObject, URLSessionDelegate {
    private let pinnedSPKIHashes: Set<String>

    init(pinnedSPKIHashesBase64: Set<String>) {
        self.pinnedSPKIHashes = pinnedSPKIHashesBase64
        super.init()
    }

    func urlSession(_ session: URLSession, didReceive challenge: URLAuthenticationChallenge,
                    completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let trust = challenge.protectionSpace.serverTrust else {
            completionHandler(.performDefaultHandling, nil)
            return
        }

        let policy = SecPolicyCreateSSL(true, challenge.protectionSpace.host as CFString)
        SecTrustSetPolicies(trust, policy)

        var error: CFError?
        guard SecTrustEvaluateWithError(trust, &error) else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }

        guard let cert = SecTrustGetCertificateAtIndex(trust, 0),
              let key = SecCertificateCopyKey(cert),
              let keyData = SecKeyCopyExternalRepresentation(key, nil) as Data? else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }

        let spkiHash = Data(SHA256.hash(data: keyData)).base64EncodedString()
        if pinnedSPKIHashes.contains(spkiHash) {
            completionHandler(.useCredential, URLCredential(trust: trust))
        } else {
            completionHandler(.cancelAuthenticationChallenge, nil)
        }
    }
}

enum APIError: Error, LocalizedError {
