    case cancelled

    var errorDescription: String? {
        switch self {
        case .invalidURL: return "Invalid URL"
        case .invalidResponse: return "Invalid response"
        case .server(let status, let message): return "Server error (\(status))\(message.map { ": \($0)" } ?? "")"
        case .decoding: return "Failed to decode response"
        case .encoding: return "Failed to encode request"
        case .unauthorized: return "Unauthorized"
        case .network(let msg): return msg
        case .timeout: return "Request timed out"
        case .cancelled: return "Request cancelled"
        }
    }
}

final class APIClient {
    let config: APIConfig
    private let session: URLSession
    private let encoder = JSONEncoder()
    private let decoder = JSONDecoder()

    init(config: APIConfig) {
        self.config = config
        encoder.dateEncodingStrategy = .iso8601
        decoder.dateDecodingStrategy = .iso8601

        let delegate = PinnedSessionDelegate(pinnedSPKIHashesBase64: config.pinnedSPKIHashesBase64)
        let configuration = URLSessionConfiguration.ephemeral
        configuration.timeoutIntervalForRequest = config.requestTimeout
        configuration.waitsForConnectivity = true
        configuration.httpAdditionalHeaders = [
            "Accept": "application/json",
            "Content-Type": "application/json"
        ]
        self.session = URLSession(configuration: configuration, delegate: delegate, delegateQueue: nil)
    }

    func request<T: Decodable>(_ path: String,
                               method: String = "GET",
                               body: Encodable? = nil,
                               query: [URLQueryItem] = [],
                               idempotencyKey: String? = nil) async throws -> T {
        guard var components = URLComponents(url: config.baseURL.appendingPathComponent(path), resolvingAgainstBaseURL: false) else {
            throw APIError.invalidURL
        }
        if !query.isEmpty { components.queryItems = query }
        guard let url = components.url else { throw APIError.invalidURL }

        var req = URLRequest(url: url)
        req.httpMethod = method
        req.setValue(config.apiKey, forHTTPHeaderField: "X-API-Key")
        if let token = SessionManager.shared.accessToken {
            req.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        if let key = idempotencyKey {
            req.setValue(key, forHTTPHeaderField: "Idempotency-Key")
        }
        req.setValue(UUID().uuidString, forHTTPHeaderField: "X-Request-Id")

        if let body = body {
            do {
                let data = try encoder.encode(AnyEncodable(body))
                req.httpBody = data
            } catch {
                throw APIError.encoding
            }
        }

        do {
            let (data, response) = try await session.data(for: req)
            guard let http = response as? HTTPURLResponse else { throw APIError.invalidResponse }
            if http.statusCode == 401 { throw APIError.unauthorized }
            guard (200...299).contains(http.statusCode) else {
                let message = (try? JSONSerialization.jsonObject(with: data)) as? [String: Any]
                throw APIError.server(status: http.statusCode, message: message?["message"] as? String)
            }
            do {
                return try decoder.decode(T.self, from: data)
            } catch {
                throw APIError.decoding
            }
        } catch is CancellationError {
            throw APIError.cancelled
        } catch let e as URLError {
            if e.code == .timedOut { throw APIError.timeout }
            throw APIError.network(e.localizedDescription)
        } catch {
            throw APIError.network(error.localizedDescription)
        }
    }
}

struct AnyEncodable: Encodable {
    private let encodeClosure: (Encoder) throws -> Void
    init(_ encodable: Encodable) { self.encodeClosure = encodable.encode }
    func encode(to encoder: Encoder) throws { try encodeClosure(encoder) }
}

// MARK: - Trading API

protocol TradingAPI {
    func getPortfolio() async throws -> Portfolio
    func getQuote(symbol: String) async throws -> Quote
    func placeOrder(_ order: OrderRequest) async throws -> OrderResponse
    func cancelOrder(orderId: UUID) async throws -> OrderResponse
    func listOrders(symbol: String?) async throws -> [OrderResponse]
}

final class TradingAPIClient: TradingAPI {
    private let api: APIClient
    init(api: APIClient) { self.api = api }

    func getPortfolio() async throws -> Portfolio {
        try await api.request("v1/portfolio", method: "GET")
    }

    func getQuote(symbol: String) async throws -> Quote {
        try await api.request("v1/quotes/\(symbol.uppercased())", method: "GET")
    }

    func placeOrder(_ order: OrderRequest) async throws -> OrderResponse {
        let idempotency = order.id.uuidString
        return try await api.request("v1/orders", method: "POST", body: order, idempotencyKey: idempotency)
    }

    func cancelOrder(orderId: UUID) async throws -> OrderResponse {
        try await api.request("v1/orders/\(orderId.uuidString)/cancel", method: "POST")
    }

    func listOrders(symbol: String?) async throws -> [OrderResponse] {
        var query: [URLQueryItem] = []
        if let symbol, !symbol.isEmpty { query.append(URLQueryItem(name: "symbol", value: symbol.uppercased())) }
        return try await api.request("v1/orders", method: "GET", query: query)
    }
}

// MARK: - Realtime Quotes (WebSocket)

enum RealtimeEvent: Codable, Hashable {
    case quote(Quote)
    case fill(TradeFill)
    case order(OrderResponse)
    case heartbeat(Date)
}

final class RealtimeClient: NSObject {
    private let baseURL: URL
    private let pinnedSPKIHashes: Set<String>
    private let apiKey: String

    private var urlSession: URLSession!
    private var task: URLSessionWebSocketTask?
    private var isConnected = Atomic(false)
    private let decoder = JSONDecoder()
    private let encoder = JSONEncoder()
    private var subscriptions = Atomic(Set<String>())
    private var reconnectAttempt = Atomic(0)
    private var pingTimer: DispatchSourceTimer?

    var onEvent: ((RealtimeEvent) -> Void)?
    var onStateChange: ((Bool) -> Void)?
    var onError: ((Error) -> Void)?

    init(baseURL: URL, apiKey: String, pinnedSPKIHashesBase64: Set<String>) {
        self.baseURL = baseURL
        self.apiKey = apiKey
        self.pinnedSPKIHashes = pinnedSPKIHashesBase64
        super.init()
        decoder.dateDecodingStrategy = .iso8601
        encoder.dateEncodingStrategy = .iso8601

        let configuration = URLSessionConfiguration.ephemeral
        configuration.waitsForConnectivity = true
        configuration.timeoutIntervalForRequest = 20
        self.urlSession = URLSession(configuration: configuration, delegate: PinnedSessionDelegate(pinnedSPKIHashesBase64: pinnedSPKIHashesBase64), delegateQueue: nil)
    }

    func connect() {
        guard !isConnected.value else { return }
        var components = URLComponents(url: baseURL, resolvingAgainstBaseURL: false)
        if components?.scheme == "https" { components?.scheme = "wss" }
        if components?.scheme == "http" { components?.scheme = "ws" }
        let wsURL = (components?.url ?? baseURL).appendingPathComponent("v1/realtime")
        var req = URLRequest(url: wsURL)
        req.setValue(apiKey, forHTTPHeaderField: "X-API-Key")
        if let token = SessionManager.shared.accessToken {
            req.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }

        task = urlSession.webSocketTask(with: req)
        task?.resume()
        isConnected.mutate { $0 = true }
        onStateChange?(true)
        reconnectAttempt.mutate { $0 = 0 }
        startPing()
        listen()
        resubscribeAll()
    }

    func disconnect() {
        stopPing()
        task?.cancel(with: .goingAway, reason: nil)
        task = nil
        isConnected.mutate { $0 = false }
        onStateChange?(false)
    }

    func subscribeQuotes(symbols: [String]) {
        subscriptions.mutate { set in
            for s in symbols { set.insert("quote:\(s.uppercased())") }
        }
        send(["type": "subscribe", "channels": symbols.map { ["name": "quotes", "symbol": $0.uppercased()] }])
    }

    func unsubscribeQuotes(symbols: [String]) {
        subscriptions.mutate { set in
            for s in symbols { set.remove("quote:\(s.uppercased())") }
        }
        send(["type": "unsubscribe", "channels": symbols.map { ["name": "quotes", "symbol": $0.uppercased()] }])
    }

    private func resubscribeAll() {
        let subs = subscriptions.value
        let symbols = subs.compactMap { key -> String? in
            if key.hasPrefix("quote:") { return String(key.dropFirst("quote:".count)) }
            return nil
        }
        if !symbols.isEmpty { subscribeQuotes(symbols: symbols) }
    }

    private func listen() {
        task?.receive { [weak self] result in
            guard let self else { return }
            switch result {
            case .failure(let error):
                self.onError?(error)
                self.handleDisconnectAndReconnect()
            case .success(let message):
                self.handle(message)
                self.listen()
            }
        }
    }

    private func handle(_ message: URLSessionWebSocketTask.Message) {
        let data: Data?
        switch message {
        case .data(let d): data = d
        case .string(let s): data = s.data(using: .utf8)
        @unknown default: data = nil
        }
        guard let data else { return }

        if let obj = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
           let type = obj["type"] as? String {
            if type == "heartbeat" {
                onEvent?(.heartbeat(Date()))
                return
            }
        }

        if let quote = try? decoder.decode(Quote.self, from: data) {
            onEvent?(.quote(quote))
            return
        }
        if let fill = try? decoder.decode(TradeFill.self, from: data) {
            onEvent?(.fill(fill))
            return
        }
        if let order = try? decoder.decode(OrderResponse.self, from: data) {
            onEvent?(.order(order))
            return
        }
    }

    private func send(_ json: [String: Any]) {
        guard let task else { return }
        guard let data = try? JSONSerialization.data(withJSONObject: json) else { return }
        task.send(.data(data)) { [weak self] error in
            if let error { self?.onError?(error) }
        }
    }

    private func startPing() {
        stopPing()
        let timer = DispatchSource.makeTimerSource(queue: .global(qos: .utility))
        timer.schedule(deadline: .now() + 10, repeating: 10)
        timer.setEventHandler { [weak self] in
            guard let self, let task = self.task else { return }
            task.sendPing { error in
                if let error {
                    self.onError?(error)
                    self.handleDisconnectAndReconnect()
                }
            }
        }
        timer.resume()
        pingTimer = timer
    }

    private func stopPing() {
        pingTimer?.cancel()
        pingTimer = nil
    }

    private func handleDisconnectAndReconnect() {
        guard isConnected.value else { return }
        isConnected.mutate { $0 = false }
        onStateChange?(false)
        stopPing()
        task?.cancel(with: .abnormalClosure, reason: nil)
        task = nil

        let attempt = reconnectAttempt.value
        let backoff = min(30.0, pow(2.0, Double(attempt)) * 1.0)
        reconnectAttempt.mutate { $0 += 1 }
        DispatchQueue.global(qos: .utility).asyncAfter(deadline: .now() + backoff) { [weak self] in
            self?.connect()
        }
    }
}

// MARK: - App State / Store

@MainActor
final class TradingStore {
    static let shared = TradingStore()

    private(set) var portfolio: Portfolio = Portfolio(cash: Money(currency: "USD", amount: 0), positions: [], updatedAt: Date())
    private(set) var quotes: [String: Quote] = [:]
    private(set) var orders: [OrderResponse] = []
    private(set) var lastError: APIError?
    private(set) var isRealtimeConnected: Bool = false
    private(set) var isLoadingPortfolio: Bool = false
    private(set) var isPlacingOrder: Bool = false

    private var api: TradingAPI!
    private var realtime: RealtimeClient!

    private var observers: [UUID: () -> Void] = [:]

    func configure(apiConfig: APIConfig) {
        let apiClient = APIClient(config: apiConfig)
        self.api = TradingAPIClient(api: apiClient)
        self.realtime = RealtimeClient(baseURL: apiConfig.baseURL, apiKey: apiConfig.apiKey, pinnedSPKIHashesBase64: apiConfig.pinnedSPKIHashesBase64)

        realtime.onStateChange = { [weak self] connected in
            Task { @MainActor in
                self?.isRealtimeConnected = connected
                self?.notify()
            }
        }
        realtime.onEvent = { [weak self] event in
            Task { @MainActor in
                self?.handle(event)
            }
        }
        realtime.onError = { [weak self] error in
            Task { @MainActor in
                self?.lastError = (error as? APIError) ?? .network(error.localizedDescription)
                self?.notify()
            }
        }
    }

    func addObserver(_ block: @escaping () -> Void) -> UUID {
        let id = UUID()
        observers[id] = block
        return id
    }

    func removeObserver(_ id: UUID) { observers.removeValue(forKey: id) }

    private func notify() { observers.values.forEach { $0() } }

    func connectRealtime() { realtime.connect() }
    func disconnectRealtime() { realtime.disconnect() }

    func subscribe(symbols: [String]) { realtime.subscribeQuotes(symbols: symbols) }

    func refreshPortfolio() async {
        isLoadingPortfolio = true
        lastError = nil
        notify()
        do {
            portfolio = try await api.getPortfolio()
            isLoadingPortfolio = false
            notify()
        } catch let e as APIError {
            lastError = e
            isLoadingPortfolio = false
            notify()
        } catch {
            lastError = .network(error.localizedDescription)
            isLoadingPortfolio = false
            notify()
        }
    }

    func refreshOrders(symbol: String? = nil) async {
        lastError = nil
        notify()
        do {
            orders = try await api.listOrders(symbol: symbol)
            notify()
        } catch let e as APIError {
            lastError = e
            notify()
        } catch {
            lastError = .network(error.localizedDescription)
            notify()
        }
    }

    func getQuote(symbol: String) async {
        lastError = nil
        notify()
        do {
            let q = try await api.getQuote(symbol: symbol)
            quotes[q.symbol] = q
            notify()
        } catch let e as APIError {
            lastError = e
            notify()
        } catch {
            lastError = .network(error.localizedDescription)
            notify()
        }
    }

    func placeOrder(symbol: String, side: OrderSide, type: OrderType, quantity: Decimal, limitPrice: Decimal?) async {
        guard quantity > 0 else { return }
        isPlacingOrder = true
        lastError = nil
        notify()
        let req = OrderRequest(id: UUID(),
                               symbol: symbol.uppercased(),
                               side: side,
                               type: type,
                               quantity: quantity.rounded(scale: 6),
                               limitPrice: (type == .limit ? limitPrice?.rounded(scale: 6) : nil),
                               clientTimestamp: Date())
        do {
            let res = try await api.placeOrder(req)
            orders.insert(res, at: 0)
            isPlacingOrder = false
            notify()
            await refreshPortfolio()
        } catch let e as APIError {
            lastError = e
            isPlacingOrder = false
            notify()
        } catch {
            lastError = .network(error.localizedDescription)
            isPlacingOrder = false
            notify()
        }
    }

    func cancelOrder(_ id: UUID) async {
        lastError = nil
        notify()
        do {
            let res = try await api.cancelOrder(orderId: id)
            if let idx = orders.firstIndex(where: { $0.id == id }) {
                orders[idx] = res
            } else {
                orders.insert(res, at: 0)
            }
            notify()
        } catch let e as APIError {
            lastError = e
            notify()
        } catch {
            lastError = .network(error.localizedDescription)
            notify()
        }
    }

    private func handle(_ event: RealtimeEvent) {
        switch event {
        case .quote(let q):
            quotes[q.symbol] = q
        case .fill(let fill):
            if let idx = orders.firstIndex(where: { $0.id == fill.orderId }) {
                var o = orders[idx]
                let newFilled = (o.filledQuantity + fill.quantity).rounded(scale: 6)
                let newAvg = computeNewAvgFill(existingAvg: o.avgFillPrice, existingQty: o.filledQuantity, fillPrice: fill.price, fillQty: fill.quantity)
                let status: OrderStatus = (newFilled >= o.quantity) ? .filled : .partial
                o = OrderResponse(id: o.id, symbol: o.symbol, side: o.side, type: o.type, quantity: o.quantity, filledQuantity: newFilled, avgFillPrice: newAvg, status: status, message: o.message, serverTimestamp: Date())
                orders[idx] = o
            }
            Task { await refreshPortfolio() }
        case .order(let o):
            if let idx = orders.firstIndex(where: { $0.id == o.id }) {
                orders[idx] = o
            } else {
                orders.insert(o, at: 0)
            }
        case .heartbeat:
            break
        }
        notify()
    }

    private func computeNewAvgFill(existingAvg: Decimal?, existingQty: Decimal, fillPrice: Decimal, fillQty: Decimal) -> Decimal? {
        let totalQty = existingQty + fillQty
        guard totalQty > 0 else { return nil }
        let existingValue = (existingAvg ?? 0) * existingQty
        let fillValue = fillPrice * fillQty
        return ((existingValue + fillValue) / totalQty).rounded(scale: 6)
    }
}

