final class OrderTicketView: UIView {
    var onPlaceOrder: ((String, OrderSide, OrderType, Decimal, Decimal?) -> Void)?

    private let symbolField = PaddedTextField()
    private let sideControl = UISegmentedControl(items: ["Buy", "Sell"])
    private let typeControl = UISegmentedControl(items: ["Market", "Limit"])
    private let qtyField = PaddedTextField()
    private let limitField = PaddedTextField()
    private let placeButton = UIButton(type: .system)

    private let formatter: NumberFormatter = {
        let f = NumberFormatter()
        f.locale = .current
        f.numberStyle = .decimal
        f.maximumFractionDigits = 6
        f.minimumFractionDigits = 0
        return f
    }()

    override init(frame: CGRect) {
        super.init(frame: frame)
        layer.cornerRadius = 16
        backgroundColor = .secondarySystemBackground

        symbolField.placeholder = "Symbol (e.g. AAPL)"
        symbolField.autocapitalizationType = .allCharacters
        symbolField.autocorrectionType = .no
        symbolField.backgroundColor = .systemBackground
        symbolField.layer.cornerRadius = 12

        sideControl.selectedSegmentIndex = 0
        typeControl.selectedSegmentIndex = 0
        typeControl.addTarget(self, action: #selector(typeChanged), for: .valueChanged)

        qtyField.placeholder = "Quantity"
        qtyField.keyboardType = .decimalPad
        qtyField.backgroundColor = .systemBackground
        qtyField.layer.cornerRadius = 12

        limitField.placeholder = "Limit Price"
        limitField.keyboardType = .decimalPad
        limitField.backgroundColor = .systemBackground
        limitField.layer.cornerRadius = 12
        limitField.isHidden = true

        placeButton.setTitle("Place Order", for: .normal)
        placeButton.titleLabel?.font = .systemFont(ofSize: 17, weight: .bold)
        placeButton.backgroundColor = .systemBlue
        placeButton.setTitleColor(.white, for: .normal)
        placeButton.layer.cornerRadius = 12
        placeButton.addTarget(self, action: #selector(placeTapped), for: .touchUpInside)

        let stack = UIStackView(arrangedSubviews: [
            labeledRow("Symbol", symbolField),
            labeledRow("Side", sideControl),
            labeledRow("Type", typeControl),
            labeledRow("Qty", qtyField),
            labeledRow("Limit", limitField),
            placeButton
        ])
        stack.axis = .vertical
        stack.spacing = 10

        addSubview(stack)
        stack.translatesAutoresizingMaskIntoConstraints = false
        NSLayoutConstraint.activate([
            stack.topAnchor.constraint(equalTo: topAnchor, constant: 14),
            stack.bottomAnchor.constraint(equalTo: bottomAnchor, constant: -14),
            stack.leadingAnchor.constraint(equalTo: leadingAnchor, constant: 14),
            stack.trailingAnchor.constraint(equalTo: trailingAnchor, constant: -14),
            placeButton.heightAnchor.constraint(equalToConstant: 48)
        ])
    }

    required init?(coder: NSCoder) { fatalError("init(coder:) has not been implemented") }

    func setSymbol(_ symbol: String) { symbolField.text = symbol.uppercased() }

    func setPlacing(_ placing: Bool) {
        placeButton.isEnabled = !placing
        placeButton.alpha = placing ? 0.6 : 1.0
        placeButton.setTitle(placing ? "Placing..." : "Place Order", for: .normal)
    }

    @objc private func typeChanged() {
        let isLimit = typeControl.selectedSegmentIndex == 1
        limitField.isHidden = !isLimit
    }

    @objc private func placeTapped() {
        endEditing(true)
        let symbol = (symbolField.text ?? "").trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        guard !symbol.isEmpty else { return }

        let side: OrderSide = (sideControl.selectedSegmentIndex == 0) ? .buy : .sell
        let type: OrderType = (typeControl.selectedSegmentIndex == 0) ? .market : .limit

        guard let qty = parseDecimal(qtyField.text), qty > 0 else { return }

        var limit: Decimal?
        if type == .limit {
            guard let l = parseDecimal(limitField.text), l > 0 else { return }
            limit = l
        }

        onPlaceOrder?(symbol, side, type, qty, limit)
    }

    private func parseDecimal(_ text: String?) -> Decimal? {
        let t = (text ?? "").replacingOccurrences(of: ",", with: "")
        return Decimal(string: t)
    }

    private func labeledRow(_ title: String, _ view: UIView) -> UIView {
        let label = UILabel()
        label.text = title
        label.font = .systemFont(ofSize: 13, weight: .semibold)
        label.textColor = .secondaryLabel

        let stack = UIStackView(arrangedSubviews: [label, view])
        stack.axis = .vertical
        stack.spacing = 6
        return stack
    }
}

