final class TradingViewController: UIViewController, UITableViewDataSource, UITableViewDelegate {
    private let store = TradingStore.shared
    private var observerId: UUID?

    private let banner = BannerView()
    private let quoteHeader = QuoteHeaderView()
    private let ticket = OrderTicketView()
    private let table = UITableView(frame: .zero, style: .insetGrouped)
    private let refresh = UIRefreshControl()
    private let connectButton = UIButton(type: .system)

    private var watchSymbol: String = "AAPL" {
        didSet {
            ticket.setSymbol(watchSymbol)
            quoteHeader.symbolLabel.text = watchSymbol
            Task { await store.getQuote(symbol: watchSymbol) }
            store.subscribe(symbols: [watchSymbol])
        }
    }

    override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .systemBackground
        title = "Trade"

        banner.isHidden = true
        banner.onDismiss = { [weak self] in
            Task { @MainActor in
                self?.store.lastError = nil
                self?.updateUI()
            }
        }

        quoteHeader.symbolLabel.text = watchSymbol
        quoteHeader.lastLabel.text = "--"
        quoteHeader.bidAskLabel.text = "Bid --  Ask --"

        ticket.setSymbol(watchSymbol)
        ticket.onPlaceOrder = { [weak self] symbol, side, type, qty, limit in
            self?.watchSymbol = symbol
            Task { await TradingStore.shared.placeOrder(symbol: symbol, side: side, type: type, quantity: qty, limitPrice: limit) }
        }

        table.dataSource = self
        table.delegate = self
        table.register(UITableViewCell.self, forCellReuseIdentifier: "cell")
        table.refreshControl = refresh
        refresh.addTarget(self, action: #selector(pulledToRefresh), for: .valueChanged)

        connectButton.setTitle("Connect Realtime", for: .normal)
        connectButton.titleLabel?.font = .systemFont(ofSize: 13, weight: .bold)
        connectButton.addTarget(self, action: #selector(connectTapped), for: .touchUpInside)

        navigationItem.rightBarButtonItem = UIBarButtonItem(customView: connectButton)

        let topStack = UIStackView(arrangedSubviews: [banner, quoteHeader, ticket])
        topStack.axis = .vertical
        topStack.spacing = 12

        let root = UIStackView(arrangedSubviews: [topStack, table])
        root.axis = .vertical
        root.spacing = 12

        view.addSubview(root)
        root.translatesAutoresizingMaskIntoConstraints = false
        NSLayoutConstraint.activate([
            root.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 12),
            root.bottomAnchor.constraint(equalTo: view.bottomAnchor),
            root.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            root.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            banner.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 16),
            banner.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -16)
        ])

        observerId = store.addObserver { [weak self] in
            Task { @MainActor in self?.updateUI() }
        }

        Task {
            await store.refreshPortfolio()
            await store.refreshOrders(symbol: nil)
            await store.getQuote(symbol: watchSymbol)
            store.connectRealtime()
            store.subscribe(symbols: [watchSymbol])
        }
    }

    deinit {
        if let id = observerId { store.removeObserver(id) }
    }

    @objc private func pulledToRefresh() {
        Task {
            await store.refreshPortfolio()
            await store.refreshOrders(symbol: nil)
            await store.getQuote(symbol: watchSymbol)
            await MainActor.run { self.refresh.endRefreshing() }
        }
    }

    @objc private func connectTapped() {
        if store.isRealtimeConnected {
            store.disconnectRealtime()
        } else {
            store.connectRealtime()
            store.subscribe(symbols: [watchSymbol])
        }
        updateUI()
    }

    private func updateUI() {
        banner.setError(store.lastError)
        ticket.setPlacing(store.isPlacingOrder)

        if let q = store.quotes[watchSymbol] {
            quoteHeader.lastLabel.text = formatMoney(q.last)
            quoteHeader.bidAskLabel.text = "Bid \(formatMoney(q.bid))   Ask \(formatMoney(q.ask))"
        } else {
            quoteHeader.lastLabel.text = "--"
            quoteHeader.bidAskLabel.text = "Bid --  Ask --"
        }

        quoteHeader.statusPill.text = store.isRealtimeConnected ? "Live" : "Offline"
        quoteHeader.statusPill.backgroundColor = store.isRealtimeConnected ? UIColor.systemGreen.withAlphaComponent(0.16) : UIColor.secondarySystemBackground
        quoteHeader.statusPill.textColor = store.isRealtimeConnected ? .systemGreen : .secondaryLabel

        connectButton.setTitle(store.isRealtimeConnected ? "Disconnect" : "Connect Realtime", for: .normal)

        table.reloadData()
    }

    private func formatMoney(_ value: Decimal) -> String {
        let f = NumberFormatter()
        f.numberStyle = .currency
        f.currencyCode = "USD"
        f.maximumFractionDigits = 4
        return f.string(from: value as NSDecimalNumber) ?? "\(value)"
    }

    func numberOfSections(in tableView: UITableView) -> Int { 3 }

    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        switch section {
        case 0: return 1
        case 1: return max(1, store.portfolio.positions.count)
        case 2: return max(1, store.orders.prefix(20).count)
        default: return 0
        }
    }

    func tableView(_ tableView: UITableView, titleForHeaderInSection section: Int) -> String? {
        switch section {
        case 0: return "Cash"
        case 1: return "Positions"
        case 2: return "Recent Orders"
        default: return nil
        }
    }

    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "cell", for: indexPath)
        cell.selectionStyle = .none
        cell.textLabel?.numberOfLines = 2
        cell.accessoryType = .none

        switch indexPath.section {
        case 0:
            let cash = store.portfolio.cash.amount
            cell.textLabel?.text = "Available: \(formatMoney(cash))"
        case 1:
            if store.portfolio.positions.isEmpty {
                cell.textLabel?.text = "No positions"
            } else {
                let p = store.portfolio.positions[indexPath.row]
                let pnl = p.unrealizedPnL
                let pnlText = formatMoney(pnl)
                cell.textLabel?.text = "\(p.symbol)  Qty \(p.quantity)\nMkt \(formatMoney(p.marketPrice))  uPnL \(pnlText)"
                cell.textLabel?.textColor = .label
                if pnl > 0 { cell.textLabel?.textColor = .systemGreen }
                if pnl < 0 { cell.textLabel?.textColor = .systemRed }
                cell.accessoryType = .disclosureIndicator
                cell.selectionStyle = .default
            }
        case 2:
            if store.orders.isEmpty {
                cell.textLabel?.text = "No orders"
            } else {
                let o = Array(store.orders.prefix(20))[indexPath.row]
                let side = (o.side == .buy) ? "BUY" : "SELL"
                let status = o.status.rawValue.uppercased()
                let filled = "\(o.filledQuantity)/\(o.quantity)"
                let price = o.avgFillPrice.map { formatMoney($0) } ?? "--"
                cell.textLabel?.text = "\(side) \(o.symbol)  \(filled)\n\(status)  Avg \(price)"
                cell.accessoryType = (o.status == .pending || o.status == .partial) ? .detailButton : .none
            }
        default: break
        }
        return cell
    }

    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        guard indexPath.section == 1, !store.portfolio.positions.isEmpty else { return }
        let p = store.portfolio.positions[indexPath.row]
        watchSymbol = p.symbol
        tableView.deselectRow(at: indexPath, animated: true)
    }

    func tableView(_ tableView: UITableView, accessoryButtonTappedForRowWith indexPath: IndexPath) {
        guard indexPath.section == 2, !store.orders.isEmpty else { return }
        let o = Array(store.orders.prefix(20))[indexPath.row]
        guard o.status == .pending || o.status == .partial else { return }

        let alert = UIAlertController(title: "Cancel Order?", message: "\(o.side.rawValue.uppercased()) \(o.symbol) \(o.quantity)", preferredStyle: .actionSheet)
        alert.addAction(UIAlertAction(title: "Cancel Order", style: .destructive, handler: { _ in
            Task { await TradingStore.shared.cancelOrder(o.id) }
        }))
        alert.addAction(UIAlertAction(title: "Dismiss", style: .cancel))
        present(alert, animated: true)
    }
}

